// components/ui/stepper/content.tsx
function StepperContent({
  value,
  forceMount = false,
  asChild = false,
  className,
  children,
  ...props
}: StepperContentProps) {
  const {
    value: currentValue,
    steps,
    getTriggerId,
    getContentId,
  } = useStepperContext("StepperContent");
  const isActive = currentValue === value;
  const hasMatchingStep = steps.some((step) => step.value === value);

  React.useEffect(() => {
    if (process.env.NODE_ENV === "production" || hasMatchingStep) {
      return;
    }

    const timeout = window.setTimeout(() => {
      console.warn(
        `StepperContent value "${value}" does not match any StepperItem. Content values should map to a step value.`
      );
    }, 0);

    return () => window.clearTimeout(timeout);
  }, [hasMatchingStep, value]);

  if (!forceMount && !isActive) {
    return null;
  }

  const Comp = asChild ? Slot : "div";

  return (
    <Comp
      id={getContentId(value)}
      role="region"
      aria-labelledby={getTriggerId(value)}
      data-slot="stepper-content"
      data-state={isActive ? "active" : "inactive"}
      hidden={forceMount ? !isActive : undefined}
      className={cn(
        "rounded-lg border border-border/70 bg-muted/25 p-4 text-sm text-foreground shadow-sm",
        className
      )}
      {...props}
    >
      {children}
    </Comp>
  );
}

markStepperPrimitive(StepperContent, STEPPER_PRIMITIVES.content);

// components/ui/stepper/navigation.tsx
async function resolveNavigationGuard(
  guard: (() => boolean | Promise<boolean>) | undefined
) {
  if (!guard) {
    return true;
  }

  return (await guard()) !== false;
}

function StepperPrevious({
  asChild = false,
  className,
  children = "Previous",
  disabled,
  onBeforePrevious,
  onClick,
  tabIndex,
  ...props
}: StepperPreviousProps) {
  const { canGoPrevious, goPrevious } = useStepperContext("StepperPrevious");
  const [isPending, setIsPending] = React.useState(false);
  const isDisabled = disabled || !canGoPrevious || isPending;
  const Comp = asChild ? Slot : "button";

  return (
    <Comp
      type={asChild ? undefined : "button"}
      disabled={asChild ? undefined : isDisabled}
      aria-disabled={isDisabled ? true : undefined}
      tabIndex={asChild && isDisabled ? -1 : tabIndex}
      data-slot="stepper-previous"
      data-disabled={isDisabled ? "" : undefined}
      className={cn(
        "inline-flex h-10 items-center justify-center gap-2 rounded-md border border-border bg-background px-4 text-sm font-medium text-foreground",
        "transition-[color,background-color,box-shadow,transform] hover:bg-muted hover:text-foreground active:scale-[0.96]",
        "focus-visible:ring-ring/50 focus-visible:ring-[3px] focus-visible:outline-none",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
        "[&>svg]:size-4 [&>svg]:shrink-0",
        className
      )}
      onClick={async (event: React.MouseEvent<HTMLButtonElement>) => {
        onClick?.(event);

        if (isDisabled) {
          event.preventDefault();
          return;
        }

        if (event.defaultPrevented) {
          return;
        }

        setIsPending(true);

        try {
          const canNavigate = await resolveNavigationGuard(onBeforePrevious);

          if (canNavigate) {
            goPrevious();
          }
        } finally {
          setIsPending(false);
        }
      }}
      {...props}
    >
      {children}
    </Comp>
  );
}

